import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {
    @Test
    void classicRacecar() {
        assertTrue(new Solution().isStrictPalindrome("racecar"));
    }

    @Test
    void capitalizationMatters() {
        assertFalse(new Solution().isStrictPalindrome("Racecar"));
    }

    @Test
    void oneCharacter() {
        assertTrue(new Solution().isStrictPalindrome("a"));
    }

    @Test
    void emptyString() {
        assertTrue(new Solution().isStrictPalindrome(""));
    }

    @Test
    void twoDifferent() {
        assertFalse(new Solution().isStrictPalindrome("ab"));
    }

    @Test
    void spacesInNonMirroredPosition() {
        // 'a'==='a', 'b' vs ' ' mismatch → false
        assertFalse(new Solution().isStrictPalindrome("ab c a"));
    }

    @Test
    void spacesMirrored() {
        // ' ab ba ' reads the same both ways — spaces in mirrored positions
        assertTrue(new Solution().isStrictPalindrome(" ab ba "));
    }

    @Test
    void evenLengthPalindrome() {
        assertTrue(new Solution().isStrictPalindrome("abba"));
    }
}
